function cercaComune(query) {
  if (!query || query.length < 2) return [];
  const q = query.toUpperCase().trim();
  return AW_COMUNI.filter(c => c[1].startsWith(q)).slice(0, 10);
}

function cercaStato(query) {
  if (!query || query.length < 2) return [];
  const q = query.toUpperCase().trim();
  return AW_STATI.filter(s => s[1].includes(q)).slice(0, 10);
}

function getCodiceComune(nome) {
  const q = nome.toUpperCase().trim();
  const found = AW_COMUNI.find(c => c[1] === q);
  return found ? found[0] : null;
}

function getCodiceStato(nome) {
  // Cerca per sigla ISO o nome
  const q = nome.toUpperCase().trim();
  // Mappatura ISO -> nome tabella
  const isoMap = {'IT':'ITALIA','DE':'GERMANIA','FR':'FRANCIA','GB':'REGNO UNITO','US':'STATI UNITI','ES':'SPAGNA','CH':'SVIZZERA','AT':'AUSTRIA','BE':'BELGIO','NL':'PAESI BASSI','PT':'PORTOGALLO','PL':'POLONIA','RO':'ROMANIA','RU':'RUSSIA','CN':'CINA','JP':'GIAPPONE','BR':'BRASILE','AR':'ARGENTINA','AU':'AUSTRALIA'};
  const nomeStato = isoMap[q] || q;
  const found = AW_STATI.find(s => s[1].toUpperCase().includes(nomeStato));
  return found ? found[0] : AW_STATI.find(s => s[1].includes('ITALIA'))?.[0] || '100000100';
}
